bool is_valid_identifier(const std::string& name) {
    if (name.empty()) return false;
    // الحرف الأول يجب أن يكون حرفًا أو شرطة سفلية
    char first = name[0];
    if (first != '_' && !std::isalpha(static_cast<unsigned char>(first))) {
        return false;
    }
    // باقي الأحرف: حروف أو أرقام أو شرطة سفلية
    for (size_t i = 1; i < name.size(); ++i) {
        char c = name[i];
        if (c != '_' && !std::isalnum(static_cast<unsigned char>(c))) {
            return false;
        }
    }
    return true;
}

