int hex_to_int(char c) {
    if (std::isdigit(static_cast<unsigned char>(c))) {
        return c - '0';
    } else if (c >= 'A' && c <= 'F') {
        return 10 + (c - 'A');
    } else if (c >= 'a' && c <= 'f') {
        return 10 + (c - 'a');
    }
    return -1; // ليس رقم هيكس
}

// مثال: تحويل "1A" لـ 26
